INSERT INTO excel_down_log
(
	idx, add_id, os, browser, ip,
 add_date, teach_idx, type, site_id
)
VALUES
(
	excel_down_log_seq.NEXTVAL, #{add_id}, #{os}, #{browser}, #{ip},
 sysdate, #{teach_idx}, #{type}, #{site_id}
)

mapper.select:
${pagingTop} SELECT a.add_id, a.os, a.browser, a.ip, to_char(a.add_date,'yyyy-mm-dd HH24:mi:ss') as add_date, a.type, b.teach_idx, b.teach_name, a.site_id, c.homepage_name FROM excel_down_log a, teach b, cms_homepage c WHERE a.teach_idx = b.teach_idx AND a.site_id = c.homepage_id
AND a.type = #{type}
AND a.${search_type} LIKE '%' || #{search_text} || '%'
AND b.${search_type} LIKE '%' || #{search_text} || '%'
AND a.add_date >= to_date(#{start_date},'yyyy-mm-dd')
AND a.add_date <= to_date(#{end_date},'yyyy-mm-dd')+1
AND a.site_id = #{site_id}
ORDER BY a.add_date DESC ${pagingBottom}

SELECT COUNT(*) FROM EXCEL_DOWN_REASON_LOG WHERE 1=1
AND type = #{type}
AND homepage_id = #{homepage_id}
AND ${search_type} LIKE '%' || #{search_text} || '%'
AND add_date >= to_date(#{start_date},'yyyy-mm-dd')
AND add_date <= to_date(#{end_date},'yyyy-mm-dd')+1

${pagingTop} SELECT idx, homepage_id, excel_down_reason, add_id, add_ip, TO_CHAR(add_date,'yyyy-mm-dd HH24:mi:ss') as add_date, menu_path, type, (SELECT B.homepage_name FROM CMS_HOMEPAGE B WHERE B.homepage_id = A.homepage_id AND ROWNUM = 1) AS homepage_name FROM EXCEL_DOWN_REASON_LOG A WHERE 1=1
AND type = #{type}
AND ${search_type} LIKE '%' || #{search_text} || '%'
AND homepage_id = #{homepage_id}
AND add_date >= to_date(#{start_date},'yyyy-mm-dd')
AND add_date <= to_date(#{end_date},'yyyy-mm-dd')+1
ORDER BY add_date DESC ${pagingBottom}

SELECT idx, homepage_id, excel_down_reason, add_id, add_ip, TO_CHAR(add_date,'yyyy-mm-dd HH24:mi:ss') as add_date, menu_path, type, (SELECT B.homepage_name FROM CMS_HOMEPAGE B WHERE B.homepage_id = A.homepage_id AND ROWNUM = 1) AS homepage_name FROM EXCEL_DOWN_REASON_LOG A WHERE 1=1
AND idx = #{idx}
AND type = #{type}
AND ${search_type} LIKE '%' || #{search_text} || '%'
AND homepage_id = #{homepage_id}
AND add_date >= to_date(#{start_date},'yyyy-mm-dd')
AND add_date <= to_date(#{end_date},'yyyy-mm-dd')+1
ORDER BY add_date DESC
